/**
 * Elematic — Scroll Typography Widget
 *
 * Trigger system: scroll-progress mapped per part.
 * Each part reveals when scroll position reaches its threshold — not on a timer.
 * This means long text reveals progressively as the user scrolls through it.
 */
( function () {
	'use strict';

	// ─── Helpers ──────────────────────────────────────────────────────────────

	function qsa( el, sel ) {
		return Array.prototype.slice.call( el.querySelectorAll( sel ) );
	}

	function escapeHtml( str ) {
		return str
			.replace( /&/g, '&amp;' )
			.replace( /</g, '&lt;' )
			.replace( />/g, '&gt;' )
			.replace( /"/g, '&quot;' );
	}

	/**
	 * Wrap each word into a clipped/unclipped span pair.
	 */
	function splitWords( el, clip ) {
		var words = el.textContent.trim().split( /\s+/ );
		el.innerHTML = words.map( function ( word ) {
			var outer = clip
				? 'display:inline-block;overflow:hidden;vertical-align:bottom;'
				: 'display:inline-block;vertical-align:bottom;';
			return (
				'<span style="' + outer + '">' +
				'<span class="elematic-st-part" style="display:inline-block;">' +
				escapeHtml( word ) + '</span></span>'
			);
		} ).join( ' ' );
		return qsa( el, '.elematic-st-part' );
	}

	/**
	 * Wrap each character into a span.
	 */
	function splitChars( el ) {
		var chars = el.textContent.trim().split( '' );
		el.innerHTML = chars.map( function ( ch ) {
			return (
				'<span class="elematic-st-part" style="display:inline-block;">' +
				( ch === ' ' ? '&nbsp;' : escapeHtml( ch ) ) + '</span>'
			);
		} ).join( '' );
		return qsa( el, '.elematic-st-part' );
	}

	/**
	 * Split text into ACTUAL rendered lines by measuring word top positions.
	 * Groups words that share the same rendered top offset → same line.
	 * Then wraps each line in a clipped block div for the mask reveal.
	 *
	 * This fixes the full-width issue: lines are measured from real layout,
	 * not guessed by word count.
	 */
	function splitLines( el ) {
		// Force block so element fills container width before measuring.
		el.style.display = 'block';
		el.style.width   = '100%';

		// Step 1: inject word spans for measurement (inline so natural wrapping occurs).
		var words = el.textContent.trim().split( /\s+/ );
		el.innerHTML = words.map( function ( w ) {
			return '<span class="elematic-st-word" style="display:inline;">' + escapeHtml( w ) + ' </span>';
		} ).join( '' );

		// Step 2: group by rendered top position.
		var wordEls = qsa( el, '.elematic-st-word' );
		var lineMap = [];
		wordEls.forEach( function ( w ) {
			var top = Math.round( w.getBoundingClientRect().top );
			var found = null;
			for ( var i = 0; i < lineMap.length; i++ ) {
				if ( lineMap[ i ].top === top ) { found = lineMap[ i ]; break; }
			}
			if ( found ) {
				found.words.push( w.textContent.trim() );
			} else {
				lineMap.push( { top: top, words: [ w.textContent.trim() ] } );
			}
		} );

		// Step 3: rebuild as clipped full-width block lines.
		el.innerHTML = lineMap.map( function ( line ) {
			return (
				'<div style="display:block;width:100%;overflow:hidden;">' +
				'<div class="elematic-st-part" style="display:block;width:100%;">' +
				escapeHtml( line.words.join( ' ' ) ) +
				'</div></div>'
			);
		} ).join( '' );

		return qsa( el, '.elematic-st-part' );
	}

	// ─── Part animation ───────────────────────────────────────────────────────

	function revealPart( part, duration, easing, toStyles ) {
		var props = Object.keys( toStyles );
		part.style.transition = props.map( function ( p ) {
			return p + ' ' + duration + 'ms ' + easing;
		} ).join( ', ' );
		props.forEach( function ( p ) { part.style[ p ] = toStyles[ p ]; } );
	}

	function hidePart( part, duration, easing, fromStyles ) {
		var props = Object.keys( fromStyles );
		part.style.transition = props.map( function ( p ) {
			return p + ' ' + duration + 'ms ' + easing;
		} ).join( ', ' );
		props.forEach( function ( p ) { part.style[ p ] = fromStyles[ p ]; } );
	}

	// ─── Scroll progress ──────────────────────────────────────────────────────

	/**
	 * Returns 0→1 as element scrolls from entering (top at viewport bottom)
	 * to exiting (bottom at viewport top).
	 */
	function getScrollProgress( el ) {
		var rect = el.getBoundingClientRect();
		var vh   = window.innerHeight;
		var prog = ( vh - rect.top ) / ( vh + rect.height );
		return Math.min( Math.max( prog, 0 ), 1 );
	}

	// ─── Effect definitions ───────────────────────────────────────────────────

	var effects = {

		'word-fade-up': {
			split:   function ( el ) { return splitWords( el, true ); },
			prepare: function ( parts ) {
				parts.forEach( function ( p ) {
					p.style.opacity = '0'; p.style.transform = 'translateY(110%)';
				} );
			},
			reveal: function ( p, dur ) {
				revealPart( p, dur, 'cubic-bezier(.23,1,.32,1)', { opacity: '1', transform: 'translateY(0)' } );
			},
			hide: function ( p, i, total, dur ) {
				hidePart( p, dur, 'cubic-bezier(.23,1,.32,1)', { opacity: '0', transform: 'translateY(110%)' } );
			},
		},

		'flow-in': {
			split:   function ( el ) { return splitChars( el ); },
			prepare: function ( parts ) {
				var mid = Math.floor( parts.length / 2 );
				parts.forEach( function ( p, i ) {
					var d = i < mid ? -1 : 1;
					p.style.opacity = '0'; p.style.transform = 'translateX(' + ( d * 70 ) + 'px)';
				} );
			},
			reveal: function ( p, dur ) {
				revealPart( p, dur, 'cubic-bezier(.23,1,.32,1)', { opacity: '1', transform: 'translateX(0)' } );
			},
			hide: function ( p, i, total, dur ) {
				var d = i < Math.floor( total / 2 ) ? -1 : 1;
				hidePart( p, dur, 'cubic-bezier(.23,1,.32,1)', { opacity: '0', transform: 'translateX(' + ( d * 70 ) + 'px)' } );
			},
		},

		'words-move': {
			split:   function ( el ) { return splitWords( el, false ); },
			prepare: function ( parts ) {
				parts.forEach( function ( p, i ) {
					var d = i % 2 === 0 ? -1 : 1;
					p.style.opacity = '0'; p.style.transform = 'translateX(' + ( d * 90 ) + 'px)';
				} );
			},
			reveal: function ( p, dur ) {
				revealPart( p, dur, 'cubic-bezier(.23,1,.32,1)', { opacity: '1', transform: 'translateX(0)' } );
			},
			hide: function ( p, i, total, dur ) {
				var d = i % 2 === 0 ? -1 : 1;
				hidePart( p, dur, 'cubic-bezier(.23,1,.32,1)', { opacity: '0', transform: 'translateX(' + ( d * 90 ) + 'px)' } );
			},
		},

		'split-reveal': {
			split:   function ( el ) { return splitWords( el, true ); },
			prepare: function ( parts ) {
				parts.forEach( function ( p, i ) {
					var d = i % 2 === 0 ? -1 : 1;
					p.style.opacity = '0'; p.style.transform = 'translateY(' + ( d * 65 ) + 'px) scaleY(0.4)';
				} );
			},
			reveal: function ( p, dur ) {
				revealPart( p, dur, 'cubic-bezier(.34,1.56,.64,1)', { opacity: '1', transform: 'translateY(0) scaleY(1)' } );
			},
			hide: function ( p, i, total, dur ) {
				var d = i % 2 === 0 ? -1 : 1;
				hidePart( p, dur, 'cubic-bezier(.34,1.56,.64,1)', { opacity: '0', transform: 'translateY(' + ( d * 65 ) + 'px) scaleY(0.4)' } );
			},
		},

		'blur-in': {
			split:   function ( el ) { return splitChars( el ); },
			prepare: function ( parts ) {
				parts.forEach( function ( p ) {
					p.style.opacity = '0'; p.style.filter = 'blur(14px)'; p.style.transform = 'scale(1.5)';
				} );
			},
			reveal: function ( p, dur ) {
				revealPart( p, dur, 'cubic-bezier(.23,1,.32,1)', { opacity: '1', filter: 'blur(0px)', transform: 'scale(1)' } );
			},
			hide: function ( p, i, total, dur ) {
				hidePart( p, dur, 'cubic-bezier(.23,1,.32,1)', { opacity: '0', filter: 'blur(14px)', transform: 'scale(1.5)' } );
			},
		},

		'emerge-up': {
			split:   function ( el ) { return splitWords( el, true ); },
			prepare: function ( parts ) {
				parts.forEach( function ( p ) { p.style.transform = 'translateY(115%)'; } );
			},
			reveal: function ( p, dur ) {
				revealPart( p, dur, 'cubic-bezier(.23,1,.32,1)', { transform: 'translateY(0)' } );
			},
			hide: function ( p, i, total, dur ) {
				hidePart( p, dur, 'cubic-bezier(.23,1,.32,1)', { transform: 'translateY(115%)' } );
			},
		},

		'wave-roll': {
			split:   function ( el ) { return splitChars( el ); },
			prepare: function ( parts ) {
				parts.forEach( function ( p ) {
					p.style.opacity = '0'; p.style.transform = 'translateY(48px) rotate(12deg)';
				} );
			},
			reveal: function ( p, dur ) {
				revealPart( p, dur, 'cubic-bezier(.34,1.56,.64,1)', { opacity: '1', transform: 'translateY(0) rotate(0deg)' } );
			},
			hide: function ( p, i, total, dur ) {
				hidePart( p, dur, 'cubic-bezier(.34,1.56,.64,1)', { opacity: '0', transform: 'translateY(48px) rotate(12deg)' } );
			},
		},

		'char-fade': {
			split:   function ( el ) { return splitChars( el ); },
			prepare: function ( parts ) {
				parts.forEach( function ( p ) { p.style.opacity = '0'; } );
			},
			reveal: function ( p, dur ) {
				revealPart( p, dur, 'ease', { opacity: '1' } );
			},
			hide: function ( p, i, total, dur ) {
				hidePart( p, dur, 'ease', { opacity: '0' } );
			},
		},

		'scale-appear': {
			split: function ( el ) {
				el.style.display = 'inline-block';
				el.style.opacity = '0';
				el.style.transform = 'scale(0.08)';
				return [ el ];
			},
			prepare: function () {},
			reveal: function ( p, dur ) {
				revealPart( p, dur, 'cubic-bezier(.34,1.56,.64,1)', { opacity: '1', transform: 'scale(1)' } );
			},
			hide: function ( p, i, total, dur ) {
				hidePart( p, dur, 'cubic-bezier(.34,1.56,.64,1)', { opacity: '0', transform: 'scale(0.08)' } );
			},
			isWhole: true,
		},

		'line-reveal': {
			split:   function ( el ) { return splitLines( el ); },
			prepare: function ( parts ) {
				parts.forEach( function ( p ) { p.style.transform = 'translateY(115%)'; } );
			},
			reveal: function ( p, dur ) {
				revealPart( p, dur, 'cubic-bezier(.23,1,.32,1)', { transform: 'translateY(0)' } );
			},
			hide: function ( p, i, total, dur ) {
				hidePart( p, dur, 'cubic-bezier(.23,1,.32,1)', { transform: 'translateY(115%)' } );
			},
		},
	};

	// ─── Scroll-scrub engine ──────────────────────────────────────────────────

	var watchers    = [];
	var scrollBound = false;

	/**
	 * In the Elementor editor the preview lives inside an iframe.
	 * The iframe's own window scroll fires correctly — window.scroll works.
	 * However the editor wraps content in a div that scrolls, not window itself.
	 * We listen on both window and document to cover all cases.
	 */
	function getScrollTarget() {
		// Inside Elementor editor iframe the scrolling container is the
		// .elementor-section-wrap or the iframe window itself.
		// Listening on window covers both editor and frontend.
		return window;
	}

	function addWatcher( watcher ) {
		watchers.push( watcher );
		if ( ! scrollBound ) {
			var target = getScrollTarget();
			target.addEventListener( 'scroll', onScroll, { passive: true } );
			target.addEventListener( 'resize', onScroll, { passive: true } );
			// Also listen on the document element in case editor scrolls a div.
			document.addEventListener( 'scroll', onScroll, { passive: true } );
			scrollBound = true;
		}
	}

	function onScroll() {
		watchers.forEach( function ( w ) { w.tick(); } );
	}

	// ─── Init ─────────────────────────────────────────────────────────────────

	function initElement( el ) {
		if ( el.dataset.elematicStInit ) { return; }
		el.dataset.elematicStInit = '1';

		var styleName = el.dataset.elematicStyle   || 'word-fade-up';
		var duration  = parseInt( el.dataset.elematicDuration, 10 ) || 600;

		var effect = effects[ styleName ] || effects[ 'word-fade-up' ];

		var parts = effect.split( el );
		if ( ! effect.isWhole ) {
			effect.prepare( parts );
		}

		var revealed = parts.map( function () { return false; } );

		// ── Scroll-scrub watcher ──────────────────────────────────────────────
		// Used on both frontend AND Elementor editor — editor iframe scrolls
		// its own window, so the same watcher works in both contexts.
		var watcher = {
			tick: function () {
				var progress = getScrollProgress( el );
				var total    = parts.length;

				parts.forEach( function ( p, i ) {
					// Spread thresholds across 0 → 0.85 of scroll progress.
					// 0.85 means the last part reveals before the element fully
					// exits the viewport, not after — natural reading feel.
					var threshold = total === 1
						? 0.1
						: ( i / ( total - 1 ) ) * 0.85;

					if ( progress >= threshold ) {
						if ( ! revealed[ i ] ) {
							effect.reveal( p, duration, i, total );
							revealed[ i ] = true;
						}
					} else {
						if ( revealed[ i ] ) {
							effect.hide( p, i, total, duration );
							revealed[ i ] = false;
						}
					}
				} );
			},
		};

		addWatcher( watcher );

		// Fire once after paint so elements in-view on load are revealed.
		setTimeout( function () { watcher.tick(); }, 150 );
	}

	function initAll() {
		var els = document.querySelectorAll( '.elematic-scroll-typography' );
		Array.prototype.forEach.call( els, function ( el ) { initElement( el ); } );
	}

	// ─── Elementor hook ───────────────────────────────────────────────────────

	window.addEventListener( 'elementor/frontend/init', function () {
		elementorFrontend.hooks.addAction(
			'frontend/element_ready/elematic-scroll-typography.default',
			function ( $scope ) {
				var el = $scope[ 0 ] ? $scope[ 0 ].querySelector( '.elematic-scroll-typography' ) : null;
				if ( el ) {
					delete el.dataset.elematicStInit;
					initElement( el );
				}
			}
		);
	} );

	// ─── Page load ────────────────────────────────────────────────────────────

	if ( document.readyState === 'loading' ) {
		document.addEventListener( 'DOMContentLoaded', initAll );
	} else {
		initAll();
	}

} )();